// Generated by Claude Opus 4.6

import { Compartment, EditorState } from '@codemirror/state';
import { oneDark } from '@codemirror/theme-one-dark';
import { EditorView } from '@codemirror/view';
import { basicSetup } from 'codemirror';
import React, { useCallback, useEffect, useRef } from 'react';

import styles from '@/components/BasicViewer/index.module.css';
import { useTheme } from '@/contexts/ThemeContext';

export type Props = {
  value: string;
  id: string;
};

const themeCompartment = new Compartment();

const lightTheme = EditorView.theme({
  '&': { fontSize: '13px' },
  '.cm-gutters': { display: 'none' },
  '.cm-activeLine': { backgroundColor: 'transparent' },
});

export const BasicViewer: React.FC<Props> = ({ value, id }) => {
  const { isDarkTheme } = useTheme();
  const viewRef = useRef<EditorView | null>(null);
  const containerRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    if (viewRef.current) {
      viewRef.current.dispatch({
        effects: themeCompartment.reconfigure(isDarkTheme ? oneDark : lightTheme),
      });
    }
  }, [isDarkTheme]);

  useEffect(() => {
    if (viewRef.current) {
      const currentContent = viewRef.current.state.doc.toString();
      if (value !== currentContent) {
        viewRef.current.dispatch({
          changes: { from: 0, to: currentContent.length, insert: value },
        });
      }
    }
  }, [value]);

  const containerRefCallback = useCallback(
    (node: HTMLDivElement | null) => {
      if (containerRef.current === node) {
        return;
      }
      containerRef.current = node;

      if (viewRef.current) {
        viewRef.current.destroy();
        viewRef.current = null;
      }

      if (!node) {
        return;
      }

      const state = EditorState.create({
        doc: value,
        extensions: [
          basicSetup,
          themeCompartment.of(isDarkTheme ? oneDark : lightTheme),
          EditorState.readOnly.of(true),
          EditorView.lineWrapping,
        ],
      });

      viewRef.current = new EditorView({ state, parent: node });
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [],
  );

  return <div className={styles.basicViewer} id={id} ref={containerRefCallback} />;
};
